mapper.select:
SELECT id, name, total_quantity, description, borrow_note, deleted_at, created_at, updated_at
FROM equipments
WHERE id = #{id}

mapper.update:
UPDATE equipments
SET name = #{name},
    total_quantity = #{totalQuantity},
    description = #{description},
    borrow_note = #{borrowNote}
WHERE id = #{id}

UPDATE equipments
SET deleted_at = NULL
WHERE id = #{id}
